void printIfPositive(int n)
{
    if (n <= 0)
    {
        return; // exit early, no value
    }
    cout << n;
}

int checkSign(int n)
{
    if (n > 0)
    {
        return 1; // function ends HERE if n > 0
    }
    if (n < 0)
    {
        return -1; // function ends HERE if n < 0
    }
    return 0; // only reached if neither above matched
}

#include <iostream>

using namespace std;

int checkSign(int n)
{
    if (n > 0)
    {
        return 1;
    }
    if (n < 0)
    {
        return -1;
    }
    return 0;
}

int main()
{
    cout << checkSign(5) << endl;
    cout << checkSign(-5) << endl;
    cout << checkSign(0) << endl;

    return 0;
}

